package main

import (
	"crypto/rand"
	"encoding/base64"
	"errors"
	"fmt"
	"net/http"
	"net/url"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	if session == nil {
		return "", errors.New("session cookie is required")
	}

	// Generate cryptographically secure random state to prevent CSRF attacks
	stateBytes := make([]byte, 16)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", fmt.Errorf("failed to generate OAuth state: %w", err)
	}
	state := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(stateBytes)

	// Determine the request scheme, respecting X-Forwarded-Proto for reverse proxies
	scheme := "http"
	if r.TLS != nil {
		scheme = "https"
	}
	if forwardedProto := r.Header.Get("X-Forwarded-Proto"); forwardedProto != "" {
		scheme = forwardedProto
	}

	// Build base URL from the request's scheme and host
	baseURL := &url.URL{
		Scheme: scheme,
		Host:   r.Host,
	}

	// Resolve the provided redirect path to an absolute URL (handles both relative and absolute paths)
	parsedRedirect, err := baseURL.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid redirect path: %w", err)
	}
	redirectURL := parsedRedirect.String()

	// Create a copy of the OAuth config with the resolved absolute redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectURL

	// Generate the authorization URL with the random state
	authURL := config.AuthCodeURL(state)

	// Create oauth_state cookie by copying attributes from the session cookie
	// This ensures the state cookie matches the session's scope (domain, path, security policies)
	// so it will be sent to the callback endpoint alongside the session cookie
	stateCookie := *session
	stateCookie.Name = "oauth_state"
	stateCookie.Value = state
	// Optional: Set short expiration (10 minutes) since state is only valid for the OAuth flow
	// stateCookie.MaxAge = 600

	// Set the state cookie in the response
	http.SetCookie(w, &stateCookie)

	return authURL, nil
}

