		return "", errors.New("redirect URL must be within the application's domain")
	}

	// Generate cryptographically secure random state for CSRF protection
	stateBytes := make([]byte, 32)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", fmt.Errorf("failed to generate secure state: %w", err)
	}
	state := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(stateBytes)

	// Create OAuth config copy with validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = resolvedRedirect.String()

	// Generate authorization URL with secure state
	authURL := config.AuthCodeURL(state)

	// Store state in short-lived secure cookie for later callback validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
