func generateRandomState() (string, error) {
	b := make([]byte, 16) // 128 bits of entropy for CSRF protection
	_, err := rand.Read(b)
	if err != nil {
		return "", fmt.Errorf("failed to generate random bytes: %w", err)
	}
	// Use URL-safe base64 without padding for compatibility with URL parameters
	return base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(b), nil
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate required session exists to associate the OAuth flow with the user
	if session == nil {
		return "", fmt.Errorf("active session is required: %w", http.ErrNoCookie)
	}

	// Parse and validate the provided redirect path/URL
	parsedRedirect, err := url.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid redirect path: %w", err)
	}

	// Convert relative path to absolute URL using the incoming request context
	if !parsedRedirect.IsAbs() {
		scheme := "http"
		if r.TLS != nil {
			scheme = "https"
		}
		parsedRedirect.Scheme = scheme
		parsedRedirect.Host = r.Host
	}

	// Create a copy of the global config to avoid modifying shared state across concurrent requests
	localConfig := *OAuthConfig
	localConfig.RedirectURL = parsedRedirect.String()

	// Generate secure random state to prevent CSRF attacks
	state, err := generateRandomState()
	if err != nil {
		return "", fmt.Errorf("failed to create OAuth state: %w", err)
	}

	// Store state in secure cookie to validate against callback request
	stateCookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		HttpOnly: true,                          // Prevent access via XSS
		Secure:   r.TLS != nil,                  // Only send over HTTPS when applicable
		SameSite: http.SameSiteLaxMode,          // Mitigate CSRF while allowing provider redirects
		MaxAge:   3600,                          // State valid for 1 hour
	}
	http.SetCookie(w, stateCookie)

	// Generate the final authorization URL with required parameters
	return localConfig.AuthCodeURL(state), nil
}

// Example main function to demonstrate usage (makes the package executable)
func main() {
	http.HandleFunc("/login", func(w http.ResponseWriter, r *http.Request) {
		// Get existing session or create a new one (example implementation)
		session, err := r.Cookie("session_id")
		if err != nil {
			// In production, use a secure random session ID and proper session storage
			session = &http.Cookie{
				Name:     "session_id",
				Value:    "example-session-id-" + base64.URLEncoding.EncodeToString(make([]byte, 8)),
				Path:     "/",
				HttpOnly: true,
				Secure:   r.TLS != nil,
				SameSite: http.SameSiteLaxMode,
