func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Prevent nil pointer panic by validating session exists
	if session == nil {
		return "", errors.New("session cookie cannot be nil")
	}

