	nonce := make([]byte, 16)
	if _, err := rand.Read(nonce); err != nil {
		return "", fmt.Errorf("failed to generate state nonce: %w", err)
	}
	randomPart := base64.URLEncoding.EncodeToString(nonce)

	// Tie state to user session to prevent CSRF across sessions
	state := fmt.Sprintf("%s:%s", session.Value, randomPart)

	// Determine request scheme (handles both HTTP and HTTPS environments)
