	fullRedirectURL := fmt.Sprintf("%s://%s%s", scheme, r.Host, redirectPath)

	// Copy global config to avoid modifying the original
	config := *OAuthConfig
	config.RedirectURL = fullRedirectURL

	// Generate final authorization URL with state parameter
	authURL := config.AuthCodeURL(state)

	// Set state cookie for later validation during callback
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,                          // Block JavaScript access to mitigate XSS
		Secure:   scheme == "https",             // Only send over HTTPS when applicable
		SameSite: http.SameSiteLaxMode,          // Mitigate CSRF risks
		Path:     "/",
		Expires:  time.Now().Add(10 * time.Minute), // Short TTL for security (10 minute flow window)
		MaxAge:   600,                           // MaxAge in seconds for broader browser support
